import{_ as s,c as a,o as e,f as i}from"./plugin-vue_export-helper.ecc8ebe5.js";const u='{"title":"\u0413\u043B\u0430\u0432\u0430 4","description":"","frontmatter":{"title":"\u0413\u043B\u0430\u0432\u0430 4","subtitle":"\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0430","tags":"malini","date":"2020-10-20T00:00:00.000Z"},"relativePath":"texts/malini-vijayottara/4.md","lastUpdated":1625428228131}',d={},m=i('<div class="stanza"><a href="#s4.1" id="s4.1" class="num">4.1</a><p>\u0423\u0441\u043B\u044B\u0448\u0430\u0432 \u044D\u0442\u043E, \u043C\u0443\u0434\u0440\u0435\u0446\u044B, \u043F\u043E\u0431\u0435\u0434\u0438\u0432\u0448\u0438\u0435 \u0433\u043D\u0435\u0432 \u0441 \u043E\u0431\u0440\u0430\u0434\u043E\u0432\u0430\u043D\u043D\u044B\u043C \u0432\u0437\u043E\u0440\u043E\u043C, \u043F\u043E\u043A\u043B\u043E\u043D\u0438\u0432\u0448\u0438\u0441\u044C \u0432\u043D\u043E\u0432\u044C, \u0441\u043A\u0430\u0437\u0430\u043B\u0438 \u0442\u0430\u043A\u0438\u0435 \u0441\u043B\u043E\u0432\u0430.</p></div><div class="stanza"><a href="#s4.2" id="s4.2" class="num">4.2</a><p>\u041A\u0430\u043A\u043E\u0432\u0430 \u0446\u0435\u043B\u044C \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u044F \u043C\u0430\u043D\u0442\u0440\u044B \u043D\u0430 \u043F\u0443\u0442\u0438 \u0439\u043E\u0433\u0438, \u043E \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0432\u043E\u043F\u0440\u043E\u0448\u0430\u043B\u0430 \u0414\u0435\u0432\u0438 \u0443 \u0412\u0435\u0440\u0445\u043E\u0432\u043D\u043E\u0433\u043E \u0412\u043B\u0430\u0434\u044B\u043A\u0438, \u0438 \u043A\u0430\u043A\u043E\u0432 \u0415\u0433\u043E \u043E\u0442\u0432\u0435\u0442, \u0431\u0435\u0437\u0434\u043E\u043D\u043D\u044B\u0439 \u043A\u0430\u043A \u043A\u043E\u043B\u043E\u0434\u0435\u0446?</p></div><div class="stanza"><a href="#s4.3" id="s4.3" class="num">4.3</a><p>\u041D\u0430 \u0441\u043A\u0430\u0437\u0430\u043D\u043D\u043E\u0435 (\u0438\u043C\u0438 \u0432\u0441\u0435\u043C\u0438) \u0432\u043C\u0435\u0441\u0442\u0435, \u0432\u0435\u043B\u0438\u043A\u0438\u0439 \u043C\u0443\u0434\u0440\u0435\u0446 \u041A\u0430\u0440\u0442\u0442\u0438\u043A\u0435\u044F \u0440\u0430\u0434\u0438 \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u044F \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0441\u043A\u0430\u0437\u0430\u043B \u0442\u0430\u043A\u0443\u044E \u0440\u0435\u0447\u044C .</p></div><div class="stanza"><a href="#s4.4" id="s4.4" class="num">4.4</a><p>\u0419\u043E\u0433\u0430, (\u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0435\u0441\u0442\u044C) \u0436\u0435\u043B\u0430\u043D\u043D\u043E\u0435 \u0415\u0434\u0438\u043D\u0441\u0442\u0432\u043E, \u0435\u0441\u0442\u044C \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C, \u043E\u0442\u043B\u0438\u0447\u043D\u0430\u044F \u043E\u0442 (\u044D\u0442\u043E\u0439) \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438. \u0422\u043E, \u0447\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E, \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u041F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u044B\u043C \u0440\u0430\u0434\u0438 \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u044F <em>\u0434\u0430\u043D\u043D\u043E\u0433\u043E</em> .</p></div><div class="stanza"><a href="#s4.5" id="s4.5" class="num">4.5</a><p>\u0417\u043D\u0430\u043D\u0438\u0435, \u0431\u0435\u0437 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u041F\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 - \u0434\u0432\u0443\u0445 \u0432\u0438\u0434\u043E\u0432. \u0420\u0430\u0434\u0438 \u0435\u0433\u043E \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u044F, \u0428\u0438\u0432\u043E\u0439 \u0440\u0430\u0437\u044A\u044F\u0441\u043D\u0435\u043D\u043E \u044D\u0442\u043E \u0417\u043D\u0430\u043D\u0438\u0435 .</p></div><div class="stanza"><a href="#s4.6" id="s4.6" class="num">4.6</a><p>\u0420\u0430\u0434\u0438 \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u044F \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0441\u0442\u0432\u0430 \u0432 \u0439\u043E\u0433\u0435 \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u044F \u043C\u0430\u043D\u0442\u0440\u044B. \u0411\u0435\u0437 \u0434\u0438\u043A\u0448\u0438 \u0439\u043E\u0433\u0430 \u043D\u0435 \u043F\u0440\u0438\u043C\u0435\u043D\u0438\u043C\u0430, \u043E \u0428\u0430\u043D\u043A\u0430\u0440\u0438!</p></div><div class="stanza"><a href="#s4.7" id="s4.7" class="num">4.7</a><p>\u041E\u043D\u0430 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0434\u0432\u043E\u044F\u043A\u043E\u0439 (\u0439\u043E\u0433\u043E\u0439) \u043A\u0430\u043A (\u0439\u043E\u0433\u0430) \u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F. \u0414\u0432\u043E\u044F\u043A\u043E \u043E\u043D\u0430 \u0432\u044B\u043F\u043E\u043B\u043D\u044F\u0435\u0442\u0441\u044F \u0438 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0435\u0435 \u043E\u0442 \u044D\u0442\u043E\u0433\u043E \u0434\u0432\u043E\u044F\u043A\u043E .</p></div><div class="stanza"><a href="#s4.8" id="s4.8" class="num">4.8</a><p>\u041D\u0435\u0442 \u043F\u0440\u0438\u0433\u043E\u0434\u043D\u043E\u0441\u0442\u0438 \u043A \u0439\u043E\u0433\u0435 (\u0435\u0441\u043B\u0438) \u043D\u0435\u0442 \u0441\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u044F \u043A \u0415\u0434\u0438\u043D\u0441\u0442\u0432\u0443 (\u0441 \u0411\u043E\u0436\u0435\u0441\u0442\u0432\u043E\u043C). \u041F\u0440\u0438\u0433\u043E\u0434\u043D\u043E\u0441\u0442\u044C \u043A \u043C\u0430\u043D\u0442\u0440\u0435 \u0447\u0435\u0440\u0435\u0437 \u0428\u0438\u0432\u0430-\u0434\u0438\u043A\u0448\u0443 (\u0441\u0430\u043C\u043E \u043F\u043E \u0441\u0435\u0431\u0435) - \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435 .</p></div><div class="stanza"><a href="#s4.9" id="s4.9" class="num">4.9</a><p>\u0423\u0441\u043B\u044B\u0448\u0430\u0432 \u044D\u0442\u0438 \u0441\u043B\u043E\u0432\u0430, \u041C\u0430\u0442\u044C \u041F\u0430\u0440\u0432\u0430\u0442\u0438 \u0441\u043E \u0432\u0437\u0434\u044B\u0431\u043B\u0435\u043D\u043D\u044B\u043C\u0438 \u0432\u043E\u043B\u043E\u0441\u043A\u0430\u043C\u0438, \u0442\u0440\u0435\u043F\u0435\u0449\u0443\u0449\u0438\u043C \u0442\u0435\u043B\u043E\u043C \u0438 \u0441\u043B\u0435\u0437\u0430\u043C\u0438 \u0432\u043D\u043E\u0432\u044C \u043E\u0431\u0440\u0430\u0442\u0438\u043B\u0430\u0441\u044C \u0441 \u0442\u0430\u043A\u043E\u0439 \u0440\u0435\u0447\u044C\u044E: \u041E, \u043B\u0443\u0447\u0448\u0438\u0435 \u043C\u0443\u0434\u0440\u0435\u0446\u044B!</p></div><div class="stanza"><a href="#s4.10" id="s4.10" class="num">4.10</a><p>\u0412 \u0442\u0435\u043B\u0435 \u043D\u0435\u0434\u0435\u043B\u0438\u043C\u043E\u0439 <em>\u043C\u0430\u043B\u0438\u043D\u0438</em> \u043A\u0430\u043A \u0431\u044B\u043B\u043E \u0443\u0441\u043B\u044B\u0448\u0430\u043D\u043E (\u041C\u043D\u043E\u0439), \u0435\u0441\u0442\u044C \u0442\u0430\u0442\u0432\u044B, \u043C\u0438\u0440\u044B, \u043F\u0430\u0434\u044B, \u043C\u0430\u043D\u0442\u0440\u044B .</p></div><div class="stanza"><a href="#s4.11" id="s4.11" class="num">4.11</a><p>\u0422\u043E, \u0447\u0442\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435\u043C \u0439\u043E\u043D\u0438, \u043F\u043E\u0432\u0435\u0434\u0430\u043D\u043D\u043E\u0435 \u041C\u043D\u0435 \u0422\u043E\u0431\u043E\u0439, \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F _\u043C\u0430\u043B\u0438\u043D\u0438, _\u043E \u0411\u043E\u0433! \u041F\u043E\u0432\u0435\u0434\u0430\u0439 \u043E \u0441\u043E\u0441\u0442\u0430\u0432\u043D\u044B\u0445 \u0447\u0430\u0441\u0442\u044F\u0445, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0445 \u0432 \u043D\u0435\u0439 .</p></div><div class="stanza"><a href="#s4.12-13" id="s4.12-13" class="num">4.12-13</a><p>\u041D\u0430 \u0440\u0435\u0447\u044C, \u0441\u043A\u0430\u0437\u0430\u043D\u043D\u0443\u044E \u0412\u0435\u043B\u0438\u043A\u043E\u0439 \u0411\u043E\u0433\u0438\u043D\u0435\u0439, \u0411\u0445\u0430\u0439\u0440\u0430\u0432\u0430 - \u0421\u043E\u043B\u043D\u0446\u0435 (\u0441\u0432\u043E\u0438\u043C) \u043F\u0440\u043E\u0441\u0442\u0435\u0440\u0442\u044B\u043C \u0441\u0438\u044F\u043D\u0438\u0435\u043C \u043E\u0441\u0432\u0435\u0449\u0430\u044E\u0449\u0435\u0435 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E (\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F), \u041D\u0430\u0434\u0435\u043B\u044F\u044E\u0449\u0438\u0439 \u043C\u043D\u043E\u0433\u043E\u0447\u0438\u0441\u043B\u0435\u043D\u043D\u044B\u043C \u0431\u043E\u0433\u0430\u0442\u0441\u0442\u0432\u043E\u043C, \u041D\u043E\u0441\u044F\u0449\u0438\u0439 \u0434\u0438\u0430\u0434\u0435\u043C\u0443, \u0433\u0438\u0440\u043B\u044F\u043D\u0434\u0443 \u0431\u043E\u0433\u043E\u0432 \u0438 \u0434\u0435\u043C\u043E\u043D\u043E\u0432, \u0438\u0433\u0440\u0430\u044E\u0447\u0438 \u043D\u0430\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0449\u0438\u0439, \u043D\u0435\u0432\u043E\u0437\u043C\u0443\u0442\u0438\u043C\u043E \u0441\u043A\u0430\u0437\u0430\u043B \u0442\u0430\u043A\u0438\u0435 \u043B\u0430\u0441\u043A\u043E\u0432\u044B\u0435 \u0441\u043B\u043E\u0432\u0430:</p></div><div class="stanza"><a href="#s4.14" id="s4.14" class="num">4.14</a><p>\u0422\u043E, \u0447\u0442\u043E \u043C\u043D\u043E\u0439 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u043C \u0439\u043E\u043D\u0438 - \u0435\u0441\u0442\u044C <em>\u043C\u0430\u043B\u0438\u043D\u0438</em>._ <em>\u041F\u043E\u0432\u0435\u0434\u0430\u044E \u0432\u0441\u0435</em> _\u043E\u0431 \u0435\u0435 \u0447\u0430\u0441\u0442\u044F\u0445 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0445 (\u0432 \u043D\u0435\u0439) .</p></div><div class="stanza"><a href="#s4.15-18" id="s4.15-18" class="num">4.15-18</a><p>\u0412 (\u0441\u043B\u043E\u0433\u0435) \u041F\u0425\u0410 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u044D\u043B\u0435\u043C\u0435\u043D\u0442 \u0437\u0435\u043C\u043B\u0438.(\u041E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435) \u0434\u0432\u0430\u0434\u0446\u0430\u0442\u044C \u0442\u0440\u0438 (\u0442\u0430\u0442\u0442\u0432\u044B) \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442 \u043E\u0442 \u0414\u0410 \u0434\u043E \u0414\u0416\u0425\u0410 \u0438 \u043E\u0442 \u0411\u0410 \u0434\u043E <em>\u043F\u0440\u0430\u0434\u0445\u0430\u043D\u044B</em>. \u0427\u0435\u0442\u044B\u0440\u043D\u0430\u0434\u0446\u0430\u0442\u044C \u0441\u043B\u043E\u0433\u043E\u0432 \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0422\u0425\u0410 - ( \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0442 \u0441\u043B\u043E\u0433\u0438) \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 <em>\u043F\u0443\u0440\u0443\u0448\u0438</em>. \u0422\u0440\u0438\u0430\u0434\u0430 \u0418, \u0414\u0410,_ _\u0413\u0425\u0410 \u0435\u0441\u0442\u044C \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u0430\u044F <em>\u0441\u0430\u043A\u0430\u043B\u0430</em> . \u0412 <em>\u0428\u0438\u0432\u0430 \u0442\u0430\u0442\u0432\u0435</em> \u0432\u044B\u0434\u0435\u043B\u044F\u044E\u0442\u0441\u044F \u0448\u0435\u0441\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u044C (\u0441\u043B\u043E\u0433\u043E\u0432) \u043E\u0442 \u0413\u0410 \u0434\u043E \u041D\u0410. \u0412\u044B\u0441\u043B\u0443\u0448\u0430\u0439 \u043E \u041F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u0430\u044F, \u043A\u0430\u043A \u043E\u043D\u043E \u0435\u0441\u0442\u044C, \u043E \u0442\u0440\u0435\u0445 \u0432\u0438\u0434\u0430\u0445 \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u043E\u0433\u043E, (\u043E\u043F\u0438\u0441\u0430\u043D\u043D\u043E\u0433\u043E) \u0440\u0430\u043D\u0435\u0435, \u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0435\u043C\u043E\u0433\u043E \u043F\u043E \u0447\u0438\u0441\u043B\u0443 \u0441\u043B\u043E\u0433\u043E\u0432 \u043D\u0430 <em>\u043A\u0430\u043B\u0443</em>, <em>\u043F\u0430\u0434\u0443</em>, <em>\u043C\u0430\u043D\u0442\u0440\u0443</em>, \u0438 <em>\u0431\u0445\u0443\u0432\u0430\u043D\u0443</em> .</p></div><div class="stanza"><a href="#s4.19-25" id="s4.19-25" class="num">4.19-25</a><p>\u0412 <em>\u043D\u0438\u0448\u043A\u0430\u043B\u0430</em> (\u043C\u0430\u043D\u0442\u0440\u0435)- \u043E\u0434\u043D\u043E\u0441\u043B\u043E\u0436\u043D\u0430\u044F <em>\u043F\u0430\u0434\u0430</em>, \u0442\u0440\u0435\u0445 \u0438 \u043E\u0434\u043D\u043E\u0441\u043B\u043E\u0436\u043D\u0430\u044F. \u0412 <em>\u0441\u0430\u043A\u0430\u043B\u0430</em> (\u043C\u0430\u043D\u0442\u0440\u0435) - \u043F\u044F\u0442\u0438, \u043E\u0434\u043D\u043E \u0438 \u0434\u0432\u0443\u0445\u0441\u043B\u043E\u0436\u043D\u0430\u044F, \u0447\u0435\u0442\u044B\u0440\u0435\u0445\u0441\u043B\u043E\u0436\u043D\u0430\u044F, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u043C\u0430\u0439\u0438- \u0434\u0432\u0443\u0445 \u0438 \u0442\u0440\u0435\u0445\u0441\u043B\u043E\u0436\u043D\u0430\u044F. \u0427\u0435\u0442\u044B\u0440\u0435\u0445\u0441\u043B\u043E\u0436\u043D\u0430\u044F (\u043F\u0430\u0434\u0430), \u043E\u0434\u043D\u043E \u0438 \u0434\u0432\u0443\u0445\u0441\u043B\u043E\u0436\u043D\u0430\u044F- \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u041A\u0430\u043B\u0430 (\u0442\u0430\u0442\u0442\u0432\u044B). \u0412 <em>\u0440\u0430\u0441\u043A\u0440\u0430\u0448\u0438\u0432\u0430\u043D\u0438\u0438</em> \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0434\u0432\u0430 \u0441\u043B\u043E\u0433\u0430, \u0432 <em>\u043F\u0440\u0430\u0434\u0445\u0430\u043D\u0435</em> - \u0442\u0440\u0438 \u0441\u043B\u043E\u0433\u0430, \u0432 <em>\u0431\u0443\u0434\u0434\u0445\u0438,</em> \u043F\u0440\u043E\u043D\u0438\u0437\u0430\u043D\u043D\u043E\u0439 \u0432\u043E\u0441\u044C\u043C\u0435\u0440\u043A\u043E\u0439 \u0431\u043E\u0433\u043E\u0432, <em>\u043F\u0430\u0434\u0430</em> \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0434\u0432\u0443\u0445\u0441\u043B\u043E\u0436\u043D\u043E\u0439. \u0427\u0435\u0442\u044B\u0440\u0435 \u043F\u0430\u0434\u044B \u0443 _\u0432\u0438\u0434\u0439\u0430 _(\u0442\u0430\u0442\u0442\u0432\u044B), \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u043F\u043E\u043B\u043E\u0432\u0438\u043D\u043E\u0439 (\u0441\u043B\u043E\u0433\u0430)- \u043F\u044F\u0442\u044C. \u0412 <em>\u043F\u0430\u0440\u0442\u0445\u0438\u0432\u0430 \u0442\u0430\u0442\u0442\u0432\u0435</em> - \u0442\u0440\u0438: \u043E\u0434\u043D\u0430, \u043E\u0434\u043D\u0430 \u0438 \u043F\u043E\u043B\u043E\u0432\u0438\u043D\u0430 \u0441\u043B\u043E\u0433\u0430. \u0412 <em>\u043F\u0443\u0440\u0443\u0448\u0430 (\u0442\u0430\u0442\u0442\u0432\u0435)</em> \u0438 <em>\u0440\u0430\u0433\u0430 (\u0442\u0430\u0442\u0442\u0432\u0435)</em> (\u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0442) \u0432\u0441\u0435 \u043C\u044B\u0441\u043B\u0438, <em>\u0432\u0430\u0440\u043D\u044B</em>, <em>\u043C\u0430\u043D\u0442\u0440\u044B</em>, <em>\u043A\u0430\u043B\u0410</em> \u0438 \u043F\u0440\u043E\u0447\u0435\u0435. \u0414\u0432\u0430 \u0441 \u043F\u043E\u043B\u043E\u0432\u0438\u043D\u043E\u0439 \u0441\u043B\u043E\u0433\u0430, (\u0421\u0410\u0423\u0425) \u043F\u0440\u043E\u043D\u0438\u0437\u044B\u0432\u0430\u044E\u0449\u0438\u0435 \u043F\u043E \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0434\u0432\u043E\u0438\u0445 \u043F\u043E \u043E\u0434\u043D\u043E\u043C\u0443 - \u044D\u0442\u043E \u043E\u0431\u0440\u0430\u0442\u043D\u043E\u0435 \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043D\u0438\u0437\u0448\u0438\u043C (\u0430\u043F\u0430\u0440\u0430). \u0422\u0440\u0438 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u044B\u0435 \u043F\u0440\u043E\u043D\u0438\u0437\u0430\u043D\u043D\u044B\u0435 \xAB\u0442\u0440\u0435\u0437\u0443\u0431\u0446\u0435\u043C\xBB (\u0410\u0423) \u0438 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0430\u044F (\u0435\u0441\u0442\u044C \u0441\u0440\u0435\u0434\u043D\u0435\u0435, \u043F\u0430\u0440\u0430\u043F\u0430\u0440\u0430). \u0412\u044B\u0441\u0448\u0438\u043C \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435\u043C \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 \u0432\u0438\u0441\u0430\u0440\u0433\u0443 .</p></div><div class="stanza"><a href="#s4.26" id="s4.26" class="num">4.26</a><p>\u0412\u0441\u0435 \u044D\u0442\u043E, \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u043E\u0435 \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442\u0441\u044F \u0439\u043E\u0433\u0438\u043D\u043E\u043C, \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u043C \u043F\u043E\u043B\u044C\u0437\u044B \u0441\u0435\u0431\u0435 \u0438 \u0434\u0440\u0443\u0433\u0438\u043C \u0438 \u043D\u0435 \u0438\u043D\u0430\u0447\u0435 .</p></div><div class="stanza"><a href="#s4.27" id="s4.27" class="num">4.27</a><p>\u0414\u0436\u043D\u0430\u043D\u0430 \u0438 \u0439\u043E\u0433\u0430- \u0434\u0432\u0430 \u0432\u0438\u0434\u0430 \u043F\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F. \u0416\u0435\u043B\u0430\u044E\u0449\u0438\u043C\u0438 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430 \u043E\u043D\u0438 \u043C\u044B\u0441\u043B\u044F\u0442\u0441\u044F \u043F\u043E \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 .</p></div><div class="stanza"><a href="#s4.28" id="s4.28" class="num">4.28</a><p>\u0417\u043D\u0430\u043D\u0438\u0435 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0442\u0440\u0435\u0445 \u0432\u0438\u0434\u043E\u0432: \u043F\u0435\u0440\u0432\u043E\u0435 - \u0441\u043B\u0443\u0448\u0430\u043D\u0438\u0435, \u0437\u0430\u0442\u0435\u043C - \u043E\u0431\u0434\u0443\u043C\u044B\u0432\u0430\u043D\u0438\u0435, \u0438 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0435 .</p></div><div class="stanza"><a href="#s4.29" id="s4.29" class="num">4.29</a><p>\u0417\u043D\u0430\u043D\u0438\u0435 \u0441\u043C\u044B\u0441\u043B\u0430 \u043F\u0438\u0441\u0430\u043D\u0438\u0439, \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0435\u043D\u043D\u043E\u0435 \u0438 \u0443\u0441\u043B\u044B\u0448\u0430\u043D\u043D\u043E\u0435 \u043C\u043D\u0435\u043D\u0438\u0435 \u043F\u0440\u0438\u043C\u0435\u043D\u044F\u0435\u0442\u0441\u044F \u0442\u0430\u043A \u0438 \u044D\u0434\u0430\u043A .</p></div><div class="stanza"><a href="#s4.30" id="s4.30" class="num">4.30</a><p>\u0417\u043D\u0430\u043D\u0438\u0435, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0438\u0437 \u0440\u0430\u0437\u043C\u044B\u0448\u043B\u0435\u043D\u0438\u044F, \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u0432\u0437\u0438\u0440\u0430\u044E\u0449\u0435\u0435 \u043D\u0430 \u0432\u0441\u0435 \u0447\u0435\u0440\u0435\u0437 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u043F\u0438\u0441\u0430\u043D\u0438\u0439, \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0434\u0432\u0443\u0445 \u0432\u0438\u0434\u043E\u0432 .</p></div><div class="stanza"><a href="#s4.31" id="s4.31" class="num">4.31</a><p>(\u041F\u0435\u0440\u0432\u043E\u0435) - \u043C\u0435\u0434\u043B\u0435\u043D\u043D\u043E\u0435, \u0447\u0435\u0440\u0435\u0437 \u0440\u0430\u0437\u043B\u0438\u0447\u0435\u043D\u0438\u0435 \u0441\u0432\u043E\u0435\u0433\u043E \xAB\u042F\xBB, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u044F, (\u0432\u0442\u043E\u0440\u043E\u0435) - \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>\u043D\u0438\u0448\u043F\u0430\u043D\u0430\u043D\u0430</em>, \u043F\u0440\u0438 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>\u0431\u0445\u0430\u0432\u0430\u043D\u0430</em> .</p></div><div class="stanza"><a href="#s4.32" id="s4.32" class="num">4.32</a><p>\u0417\u0430\u0442\u0435\u043C \u0439\u043E\u0433\u0438\u043D, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044F \u0432 \u0439\u043E\u0433\u0435, \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442 \u0439\u043E\u0433\u0438. \u0421\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0447\u0435\u0442\u044B\u0440\u0435\u043C \u0440\u0430\u0437\u043D\u043E\u0432\u0438\u0434\u043D\u043E\u0441\u0442\u044F\u043C \u0437\u043D\u0430\u043D\u0438\u044F, \u0434\u0436\u043D\u0430\u043D\u0438\u043D \u0431\u044B\u0432\u0430\u0435\u0442 \u0447\u0435\u0442\u044B\u0440\u0435\u0445 (\u0432\u0438\u0434\u043E\u0432) .</p></div><div class="stanza"><a href="#s4.33" id="s4.33" class="num">4.33</a><p>(\u042D\u0442\u043E) - \u0414\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0432\u0448\u0438\u0439, \u0440\u0430\u0437\u0440\u0443\u0448\u0438\u0432\u0448\u0438\u0439 \u0443\u043C, \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u044B\u0439 \u0438 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u0438\u0439\u0448\u0438\u0439. \u041E \u0414\u0435\u0432\u0438, \u0442\u0430\u043A\u0436\u0435 \u0439\u043E\u0433\u0438\u043D \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0447\u0435\u0442\u044B\u0440\u0435\u0445 \u0432\u0438\u0434\u043E\u0432 .</p></div><div class="stanza"><a href="#s4.34-38" id="s4.34-38" class="num">4.34-38</a><p>\u0419\u043E\u0433\u0430 \u0438\u043C\u0435\u043D\u0443\u0435\u043C\u0430\u044F <em>\u0441\u0430\u043C\u0430\u0432\u0435\u0448\u0430</em> \u0431\u044B\u0432\u0430\u0435\u0442 \u0442\u0440\u0435\u0445 \u0432\u0438\u0434\u043E\u0432: \u0442\u0430, \u043D\u0430\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442\u0441\u044F \u043F\u043E \u043B\u0438\u043D\u0438\u0438 \u043F\u0440\u0435\u0435\u043C\u0441\u0442\u0432\u0435\u043D\u043E\u0441\u0442\u0438, \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 \u043C\u0443\u0434\u0440\u044B\u043C \u043A\u0430\u043A \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u043D\u0430\u044F \u0439\u043E\u0433\u0430 \u0442\u0440\u0435\u0445 \u0432\u0438\u0434\u043E\u0432. \u0412\u043E\u0438\u0441\u0442\u0438\u043D\u0443, \u043A\u0442\u043E \u0441\u043D\u043E\u0432\u0430 \u0438 \u0441\u043D\u043E\u0432\u0430 \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u0442 \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u0435 \u0431\u0435\u0441\u043F\u043E\u043A\u043E\u0439\u0441\u0442\u0432\u0430 \u0443\u043C\u0430, \u043A \u043A\u043E\u0442\u043E\u0440\u043E\u043C\u0443 \u0441\u0442\u0440\u0435\u043C\u044F\u0442\u0441\u044F \u043C\u0443\u0434\u0440\u044B\u0435, \u0434\u043E\u0441\u0442\u0438\u0433 (\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F), \u043A\u043E\u0433\u0434\u0430 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u043D\u0435 \u043E\u043F\u0438\u0440\u0430\u0435\u0442\u0441\u044F \u043D\u0438 \u043D\u0430 \u0447\u0442\u043E \u0432\u0442\u043E\u0440\u0438\u0447\u043D\u043E\u0435. \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0441\u0438\u0434\u0434\u0445\u0430 \u0439\u043E\u0433\u0430 \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u043C\u0438 \u0443\u0441\u043F\u0435\u0445\u0430 \u0432 \u0439\u043E\u0433\u0435. \u041A\u0442\u043E \u0431\u044B \u0438 \u0433\u0434\u0435 \u0431\u044B \u043D\u0435 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043B, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0435\u0439 (\u043E\u043D) \u043D\u0430\u0441\u043B\u0430\u0434\u0438\u0442\u0441\u044F \u0435\u0435 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u043E\u043C, \u043D\u0435 \u0438\u043D\u0430\u0447\u0435. \u041E\u043D - \u0441\u0438\u0434\u0434\u0445\u0430, \u043E\u043D - \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u044B\u0439, \u043E\u043D \u043F\u043E\u0434\u043E\u0431\u0435\u043D \u0421\u0430\u0434\u0430\u0448\u0438\u0432\u0435, \u043E \u0412\u043E\u0437\u043B\u044E\u0431\u043B\u0435\u043D\u043D\u0430\u044F!</p></div><div class="stanza"><a href="#s4.39" id="s4.39" class="num">4.39</a><p>\u041A\u0430\u0436\u0434\u044B\u0439 \u043F\u043E\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0439 (\u0438\u0437 \u043D\u0430\u0437\u0432\u0430\u043D\u044B\u0445) \u0434\u0436\u043D\u0430\u043D\u0438\u043D\u043E\u0432, \u0439\u043E\u0433\u0438\u043D\u043E\u0432 \u0438 \u0441\u0438\u0434\u0434\u0445\u043E\u0432 \u0438 \u0437\u043D\u0430\u044E\u0449\u0438\u0445 \u0439\u043E\u0433\u0443 \u0432\u044B\u0448\u0435 \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0438\u0445 .</p></div><div class="stanza"><a href="#s4.40" id="s4.40" class="num">4.40</a><p>\u0422\u043E\u0442, \u043A\u0442\u043E \u043E\u0442\u0431\u0440\u0430\u0441\u044B\u0432\u0430\u0435\u0442 \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u043D\u044B\u0439 \u0440\u0430\u043D\u0435\u0435 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442 \u0439\u043E\u0433\u0438, \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043C\u0443\u0434\u0440\u044B\u043C\u0438 \u0434\u0430\u044E\u0449\u0438\u043C \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435, \u0437\u043D\u0430\u044E\u0449\u0438\u043C, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u043C \u0432 \u0437\u043D\u0430\u043D\u0438\u0438 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \xAB\u042F\xBB .</p></div><div class="stanza"><a href="#s4.41" id="s4.41" class="num">4.41</a><p>\u0418\u0442\u0430\u043A, \u0422\u0435\u0431\u0435 \u043F\u043E\u0432\u0435\u0434\u0430\u043D\u043E \u0432\u043A\u0440\u0430\u0442\u0446\u0435 \u0432\u0441\u0435 \u043E \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438 \u0442\u0430\u043D\u0442\u0440\u044B \u0434\u043B\u044F \u043F\u043E\u043B\u044C\u0437\u044B \u0439\u043E\u0433\u0438\u043D\u043E\u0432 .</p></div><p>\u0422\u0430\u043A\u043E\u0432\u0430 \u0432 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \xAB\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0435\xBB \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0430\u044F \u0433\u043B\u0430\u0432\u0430.</p>',28),c=[m];function n(p,t,l,v,r,_){return e(),a("div",null,c)}var h=s(d,[["render",n]]);export{u as __pageData,h as default};
